#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10,M=7e5+10,B=1e4;

struct Node{
    int c,x,t;
    bool operator<(Node u)const{
    	if(c!=u.c) return c<u.c;
    	if(x!=u.x) return x<u.x;
    	return t<u.t;
	}
}p[N],tmp[N];

int T,n,m,tot,ans[N],d[N];
int deg[N],head[N],ver[M],nxt[M],idx;
int q[N],hh,tt;
map<Node,int> mp;
bitset<B+10> b[N],s;
bool dead[N];

void Insert(int c,int x,int t){
    if(!mp.count({c,x,t})) p[++tot]={c,x,t},mp[p[tot]]=tot;
}

void add(int x,int y){
    ver[++idx]=x,nxt[idx]=head[y],head[y]=idx;
    deg[x]++;
}

int main(){
    scanf("%d%d%d",&T,&n,&m);
    for(int i=1;i<=n;i++){
        Insert(0,i,T+1);
        Insert(1,i,T+1);
    }
    for(int i=1;i<=m;i++){
        int c,t,x,y;
        scanf("%d%d%d%d",&c,&t,&x,&y);
        if(c==0){
            Insert(0,x,t);
            Insert(1,x,t);
            Insert(0,y,t+1);
            Insert(1,y,t+1);
            add(mp[{0,y,t+1}],mp[{0,x,t}]);
            add(mp[{1,x,t}],mp[{1,y,t+1}]);
        }else{
            Insert(0,x,t);
            Insert(1,x,t);
            Insert(0,y,t);
            Insert(1,y,t);
            add(mp[{0,x,t}],mp[{1,y,t}]);
            add(mp[{0,y,t}],mp[{1,x,t}]);
        }
    }
    for(int i=1;i<=tot;i++)
        tmp[i]=p[i];
    sort(tmp+1,tmp+tot+1);
    for(int i=2;i<=tot;i++)
        if(tmp[i-1].c==tmp[i].c && tmp[i-1].x==tmp[i].x){
            if(tmp[i].c) add(mp[tmp[i-1]],mp[tmp[i]]);
            else add(mp[tmp[i]],mp[tmp[i-1]]);
        }
    for(int k=0;k*B<n;k++){
        int hh=1,tt=0;
        for(int i=1;i<=tot;i++){
            b[i].reset();
            d[i]=deg[i];
            if(p[i].c==1 && p[i].t==T+1 &&  k*B<p[i].x && p[i].x<=(k+1)*B)
                b[i].set(p[i].x-k*B);
            if(!d[i]) q[++tt]=i;
        }
        while(hh<=tt){
            int x=q[hh++];
            for(int i=head[x];i;i=nxt[i]){
                d[ver[i]]--;
                b[ver[i]]|=b[x];
                if(!d[ver[i]])
                    q[++tt]=ver[i];
            }
        }
        s.reset();
        for(int i=k*B+1;i<=min(n,(k+1)*B);i++)
            if(b[2*i-1][i-k*B]==1){
                dead[i]=1;
                s.set(i-k*B);
            }
        for(int i=1;i<=n;i++)
            ans[i]+=min(n,(k+1)*B)-k*B-(b[2*i-1]|s).count();
    }
    for(int i=1;i<=n;i++)
        if(dead[i])
            printf("0 ");
        else
            printf("%d ",ans[i]-1);
    return 0;
}
